import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def travel_time(distance, speed):
        return distance / speed

    best_node = None
    lowest_combined_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer)
        tardiness_penalty_factor = 1.5
        earliness_penalty_factor = 0.5

        travel_t = travel_time(distance, truck_speed)
        estimated_arrival = current_time + travel_t
        start_time, end_time = time_windows[i]

        if estimated_arrival < start_time:
            # Calculate penalty for waiting
            penalty = earliness_penalty_factor * (start_time - estimated_arrival)
        elif estimated_arrival > end_time:
            # Calculate penalty for being late
            penalty = tardiness_penalty_factor * (estimated_arrival - end_time) ** 2
        else:
            # No penalty if within the window
            penalty = 0

        combined_cost = travel_t + penalty

        if combined_cost < lowest_combined_cost:
            lowest_combined_cost = combined_cost
            best_node = i

    return best_node
